for (let item of $input.all()) {
  let rawText = item.json?.content?.parts?.[0]?.text || item.json.text || item.json.message?.content || "{}";
  let cleanText = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();
  try {
    item.json.email_data = JSON.parse(cleanText);
  } catch (error) {
    // We simplified variables here to match the new prompt
    item.json.email_data = { email_subject: "AI Error", email_body: "AI Error" };
  }
}
return $input.all();
